import React, { useState } from "react";
import "./App.css";
import { BrowserRouter as Router, Routes, Route, useNavigate } from "react-router-dom";
import SOP from "./components/SOP";

// 🔹 Home Page (Modules Page)
function Home() {
  const [fileLoaded, setFileLoaded] = useState(false);
  const [fileName, setFileName] = useState("");

  const navigate = useNavigate();

  const modules = [
    "SOP Data Acquisition & NPSV Processing Module",
    "SOP Signature Extraction Module (FFT-Based)",
    "Dataset Construction & Labeling Module",
    "OCSVM-Based Anomaly Detection Module",
    "DBSCAN-Based Unsupervised Detection Module",
    "Performance Evaluation & Metrics Module"
  ];

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setFileName(file.name);
      setFileLoaded(true);
    }
  };

  return (
    <div className="container">

      <h1 className="title">
        Optical Fiber Security using SOP & Machine Learning
      </h1>

      {/* 🔹 Upload Section */}
      {!fileLoaded && (
        <div className="upload-box">
          <input type="file" onChange={handleFileUpload} />
          <p>Upload SOP Dataset (CSV)</p>
        </div>
      )}

      {/* 🔹 Module List */}
      {fileLoaded && (
        <div className="modules-box">
          <h2>Dataset Loaded: {fileName}</h2>
          <h3>System Modules</h3>

          <ul>
            {modules.map((module, index) => (
              <li key={index}>
                <button
                  className="module-btn"
                  onClick={() => {
                    if (index === 0) {
                      navigate("/sop"); // 🔥 Navigate to SOP page
                    } else {
                      alert("Module not implemented yet");
                    }
                  }}
                >
                  {module}
                </button>
              </li>
            ))}
          </ul>
        </div>
      )}

    </div>
  );
}

// 🔹 Main App Router
function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/sop" element={<SOP />} />
      </Routes>
    </Router>
  );
}

export default App;
